import{_ as t,o as n,c as s,e as o}from"./app-83da4608.js";const a={};function r(i,e){return n(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="next-js-技术要点总结" tabindex="-1"><a class="header-anchor" href="#next-js-技术要点总结" aria-hidden="true">#</a> Next.js 技术要点总结</h1><p>Next.js 是基于 React 的全栈 Web 框架，旨在提供最佳的开发体验和高性能的 Web 应用。以下是其核心技术点总结：</p><h2 id="_1-渲染模式-rendering-patterns" tabindex="-1"><a class="header-anchor" href="#_1-渲染模式-rendering-patterns" aria-hidden="true">#</a> 1. 渲染模式 (Rendering Patterns)</h2><p>Next.js 最强大的特性之一是支持多种渲染模式，开发者可以根据页面需求灵活选择：</p><ul><li><strong>SSR (Server-Side Rendering)</strong>: <ul><li><strong>服务端渲染</strong>：每次请求都在服务器端动态生成 HTML。</li><li><strong>适用场景</strong>：实时数据更新、个性化内容、SEO 要求高的页面。</li><li><strong>实现</strong>：<code>getServerSideProps</code> (Pages Router) 或直接在 Server Component 中获取数据 (App Router)。</li></ul></li><li><strong>SSG (Static Site Generation)</strong>: <ul><li><strong>静态生成</strong>：在构建时（Build Time）生成 HTML。</li><li><strong>适用场景</strong>：博客文章、文档、营销页面。</li><li><strong>实现</strong>：<code>getStaticProps</code> (Pages Router) 或默认行为 (App Router)。</li></ul></li><li><strong>ISR (Incremental Static Regeneration)</strong>: <ul><li><strong>增量静态再生</strong>：允许在应用运行时更新静态页面，无需重新构建整个站点。</li><li><strong>机制</strong>：设置 <code>revalidate</code> 时间，超时后后台重新生成页面。</li></ul></li><li><strong>CSR (Client-Side Rendering)</strong>: <ul><li><strong>客户端渲染</strong>：传统的 React 渲染方式，浏览器加载 JS 后渲染。</li><li><strong>适用场景</strong>：交互性强、无需 SEO 的私有后台页面。</li></ul></li></ul><h2 id="_2-路由系统-routing" tabindex="-1"><a class="header-anchor" href="#_2-路由系统-routing" aria-hidden="true">#</a> 2. 路由系统 (Routing)</h2><h3 id="app-router-自-next-js-13-起" tabindex="-1"><a class="header-anchor" href="#app-router-自-next-js-13-起" aria-hidden="true">#</a> App Router (自 Next.js 13 起)</h3><ul><li><strong>基于文件系统</strong>：<code>app/</code> 目录下的文件夹结构映射 URL 路径。</li><li><strong>React Server Components (RSC)</strong>: 默认所有组件都是服务端组件，减少发送到客户端的 JavaScript 体积。</li><li><strong>特殊文件</strong>：<code>page.js</code> (页面 UI), <code>layout.js</code> (共享布局), <code>loading.js</code> (加载状态), <code>error.js</code> (错误处理), <code>not-found.js</code> (404).</li><li><strong>流式传输 (Streaming)</strong>: 利用 React Suspense 逐步发送 HTML，优化首字节时间 (TTFB)。</li></ul><h3 id="pages-router-传统模式" tabindex="-1"><a class="header-anchor" href="#pages-router-传统模式" aria-hidden="true">#</a> Pages Router (传统模式)</h3><ul><li><strong>基于文件系统</strong>：<code>pages/</code> 目录下的文件映射 URL。</li><li><strong>API Routes</strong>：<code>pages/api/</code> 目录下轻松创建后端 API 端点。</li></ul><h2 id="_3-数据获取-data-fetching" tabindex="-1"><a class="header-anchor" href="#_3-数据获取-data-fetching" aria-hidden="true">#</a> 3. 数据获取 (Data Fetching)</h2><ul><li><strong>扩展的 fetch API</strong> (App Router): Next.js 扩展了原生 <code>fetch</code>，增加了缓存和重新验证控制。<div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 类似于 getStaticProps</span>
<span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;https://...&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">cache</span><span class="token operator">:</span> <span class="token string">&#39;force-cache&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// 类似于 getServerSideProps</span>
<span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;https://...&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">cache</span><span class="token operator">:</span> <span class="token string">&#39;no-store&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// ISR</span>
<span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;https://...&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token literal-property property">next</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">revalidate</span><span class="token operator">:</span> <span class="token number">10</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><strong>Server Actions</strong>: 允许在组件中直接调用异步服务端函数来处理数据突变（Mutations），无需手动创建 API 路由。</li></ul><h2 id="_4-性能优化-optimizations" tabindex="-1"><a class="header-anchor" href="#_4-性能优化-optimizations" aria-hidden="true">#</a> 4. 性能优化 (Optimizations)</h2><ul><li><strong>Image Optimization (<code>&lt;Image&gt;</code>)</strong>: 自动调整图片大小、格式转换 (WebP/AVIF)、懒加载，防止累积布局偏移 (CLS)。</li><li><strong>Font Optimization (<code>next/font</code>)</strong>: 自动托管 Google Fonts，零布局偏移。</li><li><strong>Script Optimization (<code>&lt;Script&gt;</code>)</strong>: 控制第三方脚本的加载策略 (<code>beforeInteractive</code>, <code>afterInteractive</code>, <code>lazyOnload</code>)。</li><li><strong>Turbopack</strong>: 基于 Rust 的增量打包引擎，开发服务器启动速度极快（Webpack 的替代者）。</li></ul><h2 id="_5-中间件-middleware" tabindex="-1"><a class="header-anchor" href="#_5-中间件-middleware" aria-hidden="true">#</a> 5. 中间件 (Middleware)</h2><ul><li>在请求完成之前运行代码。</li><li><strong>用途</strong>：重写、重定向、身份验证检查、修改请求/响应头、A/B 测试。</li><li><strong>运行时</strong>：基于 Edge Runtime，启动速度快，但不支持所有 Node.js API。</li></ul><h2 id="_6-部署与生态" tabindex="-1"><a class="header-anchor" href="#_6-部署与生态" aria-hidden="true">#</a> 6. 部署与生态</h2><ul><li><strong>Vercel</strong>: Next.js 的开发团队出品，提供零配置部署、Edge Network、Serverless Functions 支持。</li><li><strong>Node.js Server</strong>: 支持传统的 Node.js 服务器部署（Docker 容器化）。</li><li><strong>Static Export</strong>: <code>output: &#39;export&#39;</code> 支持导出为纯静态 HTML/CSS/JS，可部署在 Nginx、S3 等任何静态主机上。</li></ul><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>Next.js 不仅仅是一个 UI 框架，更是一个<strong>全栈元框架 (Meta-Framework)</strong>。它通过 App Router 和 Server Components 模糊了前后端的界限，极大地简化了数据流向，同时通过内置的各种优化手段，保证了应用的极致性能和 SEO 友好性。</p><h2 id="面试题" tabindex="-1"><a class="header-anchor" href="#面试题" aria-hidden="true">#</a> 面试题</h2><h3 id="_1-什么是-react-server-components-rsc-它和传统的-ssr-有什么区别" tabindex="-1"><a class="header-anchor" href="#_1-什么是-react-server-components-rsc-它和传统的-ssr-有什么区别" aria-hidden="true">#</a> 1. 什么是 React Server Components (RSC)？它和传统的 SSR 有什么区别？</h3><p><strong>答：</strong></p><ul><li><strong>React Server Components (RSC)</strong> 是 React 18 引入并在 Next.js App Router 中默认启用的组件架构。RSC 只在服务端运行，<strong>它们的 JavaScript 代码永远不会被发送到客户端</strong>。</li><li><strong>与传统 SSR 的区别</strong>： <ul><li><strong>SSR</strong>：服务端生成 HTML，但组件的代码仍然会发送到客户端进行 Hydration（水合），组件在客户端仍然是可交互的 React 组件。</li><li><strong>RSC</strong>：组件仅在服务端渲染成一种特殊的 JSON 格式（RSC Payload），客户端接收后直接映射为 DOM，不包含该组件的 JS 代码，不参与 Hydration。</li><li><strong>组合使用</strong>：在 Next.js 中，默认是 Server Components。如果需要交互（如 <code>onClick</code>、<code>useState</code>），需要在文件顶部声明 <code>&quot;use client&quot;</code> 将其标记为 Client Components。</li></ul></li></ul><h3 id="_2-next-js-中的-app-router-和-pages-router-有什么主要区别" tabindex="-1"><a class="header-anchor" href="#_2-next-js-中的-app-router-和-pages-router-有什么主要区别" aria-hidden="true">#</a> 2. Next.js 中的 App Router 和 Pages Router 有什么主要区别？</h3><p><strong>答：</strong></p><ul><li><strong>路由机制</strong>：<code>Pages Router</code> 基于 <code>pages/</code> 目录下的文件名（如 <code>pages/about.js</code> 对应 <code>/about</code>）；<code>App Router</code> 基于 <code>app/</code> 目录下的文件夹名，且必须包含 <code>page.js</code> 文件（如 <code>app/about/page.js</code> 对应 <code>/about</code>）。</li><li><strong>组件默认类型</strong>：<code>Pages Router</code> 中的组件默认是 Client Components（尽管可以 SSR）；<code>App Router</code> 中的组件默认是 React Server Components (RSC)。</li><li><strong>布局系统</strong>：<code>App Router</code> 引入了 <code>layout.js</code>，支持嵌套布局且在路由切换时不会重新渲染，状态得以保留；<code>Pages Router</code> 的布局通常需要在 <code>_app.js</code> 中全局处理或手动在每个页面包装。</li><li><strong>数据获取</strong>：<code>Pages Router</code> 依赖 <code>getServerSideProps</code>、<code>getStaticProps</code> 等 API；<code>App Router</code> 直接使用原生 <code>async/await</code> 和扩展的 <code>fetch</code> API，不再需要那些特定的导出函数。</li></ul><h3 id="_3-请解释-next-js-中的渲染模式-csr-ssr-ssg-isr-分别是什么-应该在什么场景下使用" tabindex="-1"><a class="header-anchor" href="#_3-请解释-next-js-中的渲染模式-csr-ssr-ssg-isr-分别是什么-应该在什么场景下使用" aria-hidden="true">#</a> 3. 请解释 Next.js 中的渲染模式：CSR, SSR, SSG, ISR 分别是什么，应该在什么场景下使用？</h3><p><strong>答：</strong></p><ul><li><strong>CSR (Client-Side Rendering)</strong>：客户端渲染。HTML 骨架先加载，然后下载 JS 在浏览器中请求数据并渲染。 <ul><li><em>场景</em>：高度交互的内部仪表盘、不需要 SEO 的私有页面。</li></ul></li><li><strong>SSR (Server-Side Rendering)</strong>：服务端渲染。每次用户请求时，服务器实时拉取数据并生成完整 HTML 返回。 <ul><li><em>场景</em>：数据频繁变化、高度个性化且需要 SEO 的页面（如用户主页、实时新闻）。</li></ul></li><li><strong>SSG (Static Site Generation)</strong>：静态生成。在构建时（<code>next build</code>）拉取数据并生成静态 HTML 返回，部署后直接通过 CDN 分发。 <ul><li><em>场景</em>：数据不常变化的页面（如关于我们、博客文章、帮助文档），性能极高。</li></ul></li><li><strong>ISR (Incremental Static Regeneration)</strong>：增量静态再生。允许在页面部署后，在后台定期（根据设定的时间间隔 <code>revalidate</code>）重新生成静态页面。 <ul><li><em>场景</em>：数据需要更新但不需要绝对实时，且访问量巨大的页面（如电商商品页、热门博客）。</li></ul></li></ul><h3 id="_4-next-js-13-的-app-router-中是如何进行数据获取和缓存控制的" tabindex="-1"><a class="header-anchor" href="#_4-next-js-13-的-app-router-中是如何进行数据获取和缓存控制的" aria-hidden="true">#</a> 4. Next.js 13+ 的 App Router 中是如何进行数据获取和缓存控制的？</h3><p><strong>答：</strong> 在 App Router 中，Next.js 扩展了原生的 <code>fetch</code> API，直接通过传递不同的 <code>cache</code> 或 <code>next</code> 参数来控制缓存行为，取代了原来的 <code>getStaticProps</code> 等 API：</p><ul><li><strong>SSG 等效</strong>：<code>fetch(url, { cache: &#39;force-cache&#39; })</code> （默认行为），数据在构建时被缓存，后续请求直接读取缓存。</li><li><strong>SSR 等效</strong>：<code>fetch(url, { cache: &#39;no-store&#39; })</code>，不缓存数据，每次请求都重新向服务端发起抓取。</li><li><strong>ISR 等效</strong>：<code>fetch(url, { next: { revalidate: 60 } })</code>，缓存数据，但每隔 60 秒在后台重新验证并更新缓存。</li></ul><h3 id="_5-在-next-js-中-如何优化图片加载-next-image-的核心原理" tabindex="-1"><a class="header-anchor" href="#_5-在-next-js-中-如何优化图片加载-next-image-的核心原理" aria-hidden="true">#</a> 5. 在 Next.js 中，如何优化图片加载？（<code>next/image</code> 的核心原理）</h3><p><strong>答：</strong> Next.js 提供了 <code>&lt;Image /&gt;</code> 组件来替代原生的 <code>&lt;img&gt;</code> 标签，其核心优化包括：</p><ul><li><strong>尺寸优化</strong>：根据设备的屏幕尺寸，自动提供正确大小的图片，避免在手机上加载桌面级大图。</li><li><strong>格式转换</strong>：自动将图片转换为现代 Web 格式（如 WebP、AVIF），大幅减小体积。</li><li><strong>懒加载 (Lazy Loading)</strong>：默认情况下，图片只有在滚动到视口 (Viewport) 时才会加载，节省初始带宽。</li><li><strong>防止布局偏移 (CLS)</strong>：强制要求提供 <code>width</code> 和 <code>height</code>（或使用 <code>fill</code>），在图片加载前预留占位空间，避免页面抖动。</li></ul><h3 id="_6-next-js-的-middleware-中间件-是什么-有哪些常见的应用场景" tabindex="-1"><a class="header-anchor" href="#_6-next-js-的-middleware-中间件-是什么-有哪些常见的应用场景" aria-hidden="true">#</a> 6. Next.js 的 Middleware (中间件) 是什么？有哪些常见的应用场景？</h3><p><strong>答：</strong></p><ul><li><strong>定义</strong>：Middleware 是一段在请求完成并返回响应之前运行的代码。它运行在轻量级的 Edge Runtime 中（V8 引擎），速度极快。</li><li><strong>应用场景</strong>： <ol><li><strong>鉴权与授权</strong>：检查请求中的 Token 或 Cookie，未登录则重定向到登录页。</li><li><strong>A/B 测试</strong>：根据用户特征或随机算法，将请求重写 (rewrite) 到不同的页面变体。</li><li><strong>国际化 (i18n)</strong>：根据请求头的 <code>Accept-Language</code> 或地理位置，重定向到对应的语言路由（如 <code>/en</code> 或 <code>/zh</code>）。</li><li><strong>Bot 拦截与限流</strong>：识别恶意爬虫并拦截，或做简单的 API 限流。</li></ol></li></ul><h3 id="_7-什么是-server-actions-它解决了什么问题" tabindex="-1"><a class="header-anchor" href="#_7-什么是-server-actions-它解决了什么问题" aria-hidden="true">#</a> 7. 什么是 Server Actions？它解决了什么问题？</h3><p><strong>答：</strong></p><ul><li><strong>定义</strong>：Server Actions 是 Next.js 提供的一种在服务端执行的异步函数。它们可以直接在 React 组件中被调用（例如绑定到 <code>&lt;form action={...}&gt;</code> 或按钮的 <code>onClick</code> 中）。</li><li><strong>解决的问题</strong>： <ul><li><strong>消除冗余的 API 路由</strong>：以前提交表单需要前端写 <code>fetch</code> 请求，后端写一个专门的 API Route 接收数据。现在前端直接调用 Server Action，Next.js 底层自动处理 RPC 通信。</li><li><strong>渐进式增强</strong>：在 JavaScript 加载完成甚至被禁用的情况下，HTML 表单仍然可以正常提交到 Server Action。</li><li><strong>强类型</strong>：前后端代码在同一个文件中，可以完美共享 TypeScript 类型，避免接口字段对不上的问题。</li></ul></li></ul><h3 id="_8-next-js-中如何进行-seo-优化" tabindex="-1"><a class="header-anchor" href="#_8-next-js-中如何进行-seo-优化" aria-hidden="true">#</a> 8. Next.js 中如何进行 SEO 优化？</h3><p><strong>答：</strong></p><ul><li><strong>服务端渲染 (SSR/SSG)</strong>：保证爬虫抓取到的是完整的 HTML 内容，而不是空挂载点。</li><li><strong>Metadata API</strong>：在 App Router 中，可以通过导出一个 <code>metadata</code> 对象或 <code>generateMetadata</code> 函数来动态生成 <code>&lt;title&gt;</code>、<code>&lt;meta name=&quot;description&quot;&gt;</code>、Open Graph 标签等。<div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">export</span> <span class="token keyword">const</span> metadata <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">title</span><span class="token operator">:</span> <span class="token string">&#39;我的应用&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">description</span><span class="token operator">:</span> <span class="token string">&#39;这是应用的描述&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><strong>动态 Sitemap 和 Robots.txt</strong>：支持在 <code>app/</code> 目录下直接创建 <code>sitemap.ts</code> 和 <code>robots.ts</code> 动态生成这些对搜索引擎至关重要的文件。</li><li><strong>Canonical URLs</strong>：通过 Metadata 轻松配置规范链接，防止内容重复惩罚。</li></ul>`,45)])])}const l=t(a,[["render",r],["__file","next.html.vue"]]);export{l as default};
